return items.map(item => {
  return {
    json: {
      wikitext: item.json.parse.wikitext
    }
  };
});

const wikitext = items[0].json.wikitext;

// Separar tablas wikitable
const tables = wikitext.split('{|').slice(1).map((t, i) => {
  const content = '{|' + t.split('|}')[0] + '|}';

  return {
    table_index: i,
    content,
    isMatchday: /Jornada\s+\d+/i.test(content)
  };
});

return tables.map(t => ({ json: t }));

return items.filter(item => {
  const content = item.json.content || "";

  const hasMatchday = /Jornada\s+\d+/i.test(content);
  const hasLocal = /Local/i.test(content);
  const hasResultado = /Resultado/i.test(content);
  const hasVisitante = /Visitante/i.test(content);
  const hasEstadio = /Estadio/i.test(content);
  const hasFecha = /Fecha/i.test(content);
  const hasHora = /Hora/i.test(content);

  return hasMatchday && hasLocal && hasResultado && hasVisitante && hasEstadio && hasFecha && hasHora;
});

const results = [];

function cleanCell(value) {
  if (!value) return null;

  return String(value)
    .replace(/\[\[|\]\]/g, "")
    .replace(/\{\{.*?\}\}/g, "")
    .replace(/<.*?>/g, "")
    .replace(/\[https?:\/\/[^\s\]]+/g, "")
    .replace(/\[|\]/g, "")
    .replace(/bgcolor=.*?\|/gi, "")
    .replace(/style=.*?\|/gi, "")
    .replace(/rowspan="?\d+"?\|/gi, "")
    .replace(/colspan="?\d+"?\|/gi, "")
    .replace(/rowspan=\d+\|/gi, "")
    .replace(/colspan=\d+\|/gi, "")
    .replace(/\{\{bandera2?\|.*?\}\}/gi, "")
    .replace(/\{\{flagicon\|.*?\}\}/gi, "")
    .replace(/'''/g, "")
    .replace(/''/g, "")
    .replace(/\(\s*\)/g, "")
    .replace(/\s+/g, " ")
    .trim();
}

function isScore(value) {
  return /^\d+\s*[–-]\s*\d+$/.test(value || "");
}

function isTime(value) {
  return /^(\d{1,2}:\d{2})$/.test(value || "");
}

function isAttendance(value) {
  return /^\d{4,6}$/.test(value || "");
}

function isDate(value) {
  return /^(\d{1,2}\s+de\s+\w+|\d{1,2}\s+\w+)$/i.test(value || "");
}

function normalizeScore(value) {
  return value.replace(/\s+/g, "").replace("-", "–");
}

for (const item of items) {
  const content = item.json.content || "";

  const jornadaMatch = content.match(/Jornada\s+(\d+)/i);
  const matchday = jornadaMatch ? parseInt(jornadaMatch[1], 10) : null;

  const rows = content.split("|-").slice(1);

  let currentDate = null;
  let currentTime = null;

  for (const row of rows) {
    const rawCols = row
      .split("\n")
      .map(l => l.trim())
      .filter(l => l.startsWith("|") && !l.startsWith("|+"))
      .map(l => l.replace(/^\|+/, "").trim());

    const cols = rawCols.map(cleanCell).filter(v => v && v !== "—");

    if (!cols.length) continue;

    const joined = cols.join(" | ").toLowerCase();
    if (
      joined.includes("local") &&
      joined.includes("visitante") &&
      joined.includes("resultado")
    ) {
      continue;
    }

    // Primero capturamos fecha/hora de cualquier celda de la fila
    for (const col of cols) {
      if (isDate(col)) currentDate = col;
      if (isTime(col)) currentTime = col;
    }

    const scoreIndex = cols.findIndex(isScore);
    if (scoreIndex === -1) continue;

    const score = normalizeScore(cols[scoreIndex]);
    const [home_score, away_score] = score.split("–").map(n => parseInt(n, 10));

    const before = cols.slice(0, scoreIndex);
    const after = cols.slice(scoreIndex + 1);

    const possibleHome = before.filter(v => !isDate(v) && !isTime(v) && !isAttendance(v));
    const home_team = possibleHome.length ? possibleHome[possibleHome.length - 1] : null;

    let away_team = null;
    let stadium = null;
    let attendance = null;

    const afterNonNumeric = after.filter(v => !isAttendance(v) && !isTime(v) && !isDate(v));

    if (afterNonNumeric.length >= 1) away_team = afterNonNumeric[0];
    if (afterNonNumeric.length >= 2) stadium = afterNonNumeric[1];

    const att = after.find(isAttendance);
    if (att) attendance = parseInt(att, 10);

    if (!home_team || !away_team) continue;

    if (stadium && stadium.includes("/")) {
      const parts = stadium.split("/").map(s => s.trim()).filter(Boolean);
      if (parts.length >= 2 && parts[0].toLowerCase() === parts[1].toLowerCase()) {
        stadium = parts[0];
      }
    }

    results.push({
      matchday,
      date: currentDate,
      time: currentTime,
      home_team,
      away_team,
      score,
      stadium,
      attendance,
      home_score,
      away_score,
      source: "wikipedia",
      competition: "UEFA Champions League",
      season: "2024/25",
      stage: "league_phase"
    });
  }
}

return results.map(r => ({ json: r }));

function cleanText(value) {
  if (value === null || value === undefined) return null;

  let v = String(value)
    .replace(/\u00a0/g, " ")
    .replace(/\s+/g, " ")
    .trim();

  if (!v) return null;
  if (v.toLowerCase() === "null") return null;
  return v;
}

function dedupeSlashName(value) {
  if (!value) return value;

  const parts = value.split("/").map(s => s.trim()).filter(Boolean);
  if (parts.length !== 2) return value;

  const a = parts[0].toLowerCase();
  const b = parts[1].toLowerCase();

  if (a === b) return parts[0];
  return value;
}

function normalizeDate(value) {
  value = cleanText(value);
  if (!value) return null;

  return value
    .replace(/\s+de\s+/gi, " de ")
    .replace(/\s+/g, " ")
    .trim();
}

function normalizeTime(value) {
  value = cleanText(value);
  if (!value) return null;

  const m = value.match(/^(\d{1,2}):(\d{2})$/);
  if (!m) return null;

  const hh = String(parseInt(m[1], 10)).padStart(2, "0");
  const mm = m[2];
  return `${hh}:${mm}`;
}

function normalizeTeam(value) {
  value = cleanText(value);
  if (!value) return null;

  return value
    .replace(/\s+\(\w+\)$/i, "")
    .replace(/\s+/g, " ")
    .trim();
}

function normalizeStadium(value) {
  value = cleanText(value);
  if (!value) return null;

  value = dedupeSlashName(value);

  return value
    .replace(/\s+\(\(\)\)$/g, "")
    .replace(/\s+\)$/g, "")
    .replace(/\{\{.*?\}\}/g, "")
    .replace(/\s+/g, " ")
    .trim();
}

function normalizeScore(value) {
  value = cleanText(value);
  if (!value) return null;

  value = value.replace(/-/g, "–").replace(/\s+/g, "");
  return /^\d+–\d+$/.test(value) ? value : null;
}

function normalizeAttendance(value) {
  if (value === null || value === undefined || value === "") return null;

  const digits = String(value).replace(/\D/g, "");
  if (!digits) return null;

  const n = parseInt(digits, 10);
  return Number.isNaN(n) ? null : n;
}

const out = [];
const seen = new Set();

for (const item of items) {
  const m = item.json || {};

  const matchday = m.matchday ?? null;
  const date = normalizeDate(m.date);
  const time = normalizeTime(m.time);
  const home_team = normalizeTeam(m.home_team);
  const away_team = normalizeTeam(m.away_team);
  const score = normalizeScore(m.score);
  const stadium = normalizeStadium(m.stadium);
  const attendance = normalizeAttendance(m.attendance);

  const home_score =
    m.home_score !== undefined && m.home_score !== null ? Number(m.home_score) : null;
  const away_score =
    m.away_score !== undefined && m.away_score !== null ? Number(m.away_score) : null;

  // Filtrar basura
  if (!home_team || !away_team || !score) continue;
  if (!Number.isInteger(home_score) || !Number.isInteger(away_score)) continue;

  const dedupeKey = [
    m.competition || "UEFA Champions League",
    m.season || "2024/25",
    m.stage || "league_phase",
    matchday,
    date,
    time,
    home_team,
    away_team,
    score
  ].join("|");

  if (seen.has(dedupeKey)) continue;
  seen.add(dedupeKey);

  out.push({
    json: {
      competition: cleanText(m.competition) || "UEFA Champions League",
      season: cleanText(m.season) || "2024/25",
      stage: cleanText(m.stage) || "league_phase",
      matchday: matchday,
      date: date,
      time: time,
      home_team: home_team,
      away_team: away_team,
      score: score,
      home_score: home_score,
      away_score: away_score,
      stadium: stadium,
      attendance: attendance,
      source: cleanText(m.source) || "wikipedia"
    }
  });
}

return out;

const wikitext = items[0].json.wikitext;

if (!wikitext) {
  throw new Error("No hay wikitext");
}

const start = wikitext.indexOf("=== Eliminatorias ===");
const end = wikitext.indexOf("=== Ronda preliminar ===");

if (start === -1 || end === -1 || end <= start) {
  throw new Error("No se encontró el bloque de eliminatorias");
}

const bracketText = wikitext.slice(start, end);

return [
  {
    json: {
      bracketText
    }
  }
];

const text = items[0].json.bracketText;

function getValue(key) {
  const re = new RegExp(`\\|\\s*${key}\\s*=\\s*(.+)`);
  const m = text.match(re);
  return m ? m[1].trim() : null;
}

function cleanWiki(value) {
  if (!value) return null;

  return String(value)
    .replace(/\{\{bandera\|[^}]+\}\}/gi, "")
    .replace(/\{\{esd\|([^}]+)\}\}/gi, "$1")
    .replace(/\{\{small\|([^}]+)\}\}/gi, "$1")
    .replace(/\[\[([^|\]]+)\|([^\]]+)\]\]/g, "$2")
    .replace(/\[\[([^\]]+)\]\]/g, "$1")
    .replace(/'''/g, "")
    .replace(/''/g, "")
    .replace(/<small>.*?<\/small>/gi, "")
    .replace(/<br\s*\/?>/gi, " ")
    .replace(/&nbsp;/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

const roundMap = {
  RD1: "round_of_16",
  RD2: "quarter_final",
  RD3: "semi_final",
  RD4: "final"
};

const out = [];

for (const roundKey of ["RD1", "RD2", "RD3"]) {
  const roundName = roundMap[roundKey];
  const roundDate = cleanWiki(getValue(`${roundKey}-date`));

  for (let i = 1; i <= 16; i += 2) {
    const n1 = String(i).padStart(2, "0");
    const n2 = String(i + 1).padStart(2, "0");

    const team1 = cleanWiki(getValue(`${roundKey}-team${n1}`));
    const team2 = cleanWiki(getValue(`${roundKey}-team${n2}`));

    if (!team1 || !team2) continue;

    const score1_1 = getValue(`${roundKey}-score${n1}-1`);
    const score1_2 = getValue(`${roundKey}-score${n1}-2`);
    const score1_3 = getValue(`${roundKey}-score${n1}-3`);

    const score2_1 = getValue(`${roundKey}-score${n2}-1`);
    const score2_2 = getValue(`${roundKey}-score${n2}-2`);
    const score2_3 = getValue(`${roundKey}-score${n2}-3`);

    out.push({
      competition: "UEFA Champions League",
      season: "2024/25",
      stage: roundName,
      round_dates: roundDate,
      team_1: team1,
      team_2: team2,
      team_1_leg1: score1_1 ? Number(score1_1) : null,
      team_1_leg2: score1_2 ? Number(score1_2) : null,
      team_1_agg: score1_3 ? cleanWiki(score1_3) : null,
      team_2_leg1: score2_1 ? Number(score2_1) : null,
      team_2_leg2: score2_2 ? Number(score2_2) : null,
      team_2_agg: score2_3 ? cleanWiki(score2_3) : null,
      source: "wikipedia"
    });
  }
}

// Final
const finalDate = cleanWiki(getValue("RD4-date"));
const finalTeam1 = cleanWiki(getValue("RD4-team01"));
const finalTeam2 = cleanWiki(getValue("RD4-team02"));
const finalScore1 = getValue("RD4-score01");
const finalScore2 = getValue("RD4-score02");

if (finalTeam1 && finalTeam2) {
  out.push({
    competition: "UEFA Champions League",
    season: "2024/25",
    stage: "final",
    round_dates: finalDate,
    team_1: finalTeam1,
    team_2: finalTeam2,
    team_1_leg1: null,
    team_1_leg2: null,
    team_1_agg: finalScore1 ? cleanWiki(finalScore1) : null,
    team_2_leg1: null,
    team_2_leg2: null,
    team_2_agg: finalScore2 ? cleanWiki(finalScore2) : null,
    source: "wikipedia"
  });
}

return out.map(x => ({ json: x }));

function cleanText(v) {
  if (v === null || v === undefined) return null;
  const s = String(v).replace(/\s+/g, " ").trim();
  return s || null;
}

function toIntOrNull(v) {
  if (v === null || v === undefined || v === "") return null;
  const n = parseInt(String(v).replace(/\D/g, ""), 10);
  return Number.isNaN(n) ? null : n;
}

const seen = new Set();
const out = [];

for (const item of items) {
  const m = item.json;

  const row = {
    competition: cleanText(m.competition) || "UEFA Champions League",
    season: cleanText(m.season) || "2024/25",
    stage: cleanText(m.stage),
    round_dates: cleanText(m.round_dates),
    team_1: cleanText(m.team_1),
    team_2: cleanText(m.team_2),
    team_1_leg1: toIntOrNull(m.team_1_leg1),
    team_1_leg2: toIntOrNull(m.team_1_leg2),
    team_1_agg: cleanText(m.team_1_agg),
    team_2_leg1: toIntOrNull(m.team_2_leg1),
    team_2_leg2: toIntOrNull(m.team_2_leg2),
    team_2_agg: cleanText(m.team_2_agg),
    source: cleanText(m.source) || "wikipedia"
  };

  if (!row.team_1 || !row.team_2 || !row.stage) continue;

  const key = [
    row.competition,
    row.season,
    row.stage,
    row.team_1,
    row.team_2,
    row.team_1_agg,
    row.team_2_agg
  ].join("|");

  if (seen.has(key)) continue;
  seen.add(key);

  out.push({ json: row });
}

return out;

function cleanText(v) {
  if (v === null || v === undefined) return null;
  const s = String(v)
    .replace(/<small>.*?<\/small>/gi, "")
    .replace(/\{\{.*?\}\}/g, "")
    .replace(/\[\[([^|\]]+)\|([^\]]+)\]\]/g, "$2")
    .replace(/\[\[([^\]]+)\]\]/g, "$1")
    .replace(/'''/g, "")
    .replace(/''/g, "")
    .replace(/\s+/g, " ")
    .trim();
  return s || null;
}

const out = [];

for (const item of items) {
  const m = item.json;

  const competition = cleanText(m.competition) || "UEFA Champions League";
  const season = cleanText(m.season) || "2024/25";
  const stage = cleanText(m.stage);
  const round_dates = cleanText(m.round_dates);
  const team1 = cleanText(m.team_1);
  const team2 = cleanText(m.team_2);

  const t1l1 = m.team_1_leg1 ?? null;
  const t1l2 = m.team_1_leg2 ?? null;
  const t2l1 = m.team_2_leg1 ?? null;
  const t2l2 = m.team_2_leg2 ?? null;
  const t1agg = cleanText(m.team_1_agg);
  const t2agg = cleanText(m.team_2_agg);
  const source = cleanText(m.source) || "wikipedia";

  if (!team1 || !team2 || !stage) continue;

  if (stage === "final") {
    out.push({
      json: {
        competition,
        season,
        stage,
        leg: "final",
        round_dates,
        date: null,
        time: null,
        home_team: team1,
        away_team: team2,
        home_score: t1agg !== null ? parseInt(String(t1agg).replace(/\D/g, ""), 10) : null,
        away_score: t2agg !== null ? parseInt(String(t2agg).replace(/\D/g, ""), 10) : null,
        score:
          t1agg !== null && t2agg !== null
            ? `${parseInt(String(t1agg).replace(/\D/g, ""), 10)}–${parseInt(String(t2agg).replace(/\D/g, ""), 10)}`
            : null,
        stadium: null,
        attendance: null,
        source
      }
    });
    continue;
  }

  if (t1l1 !== null && t2l1 !== null) {
    out.push({
      json: {
        competition,
        season,
        stage,
        leg: "first_leg",
        round_dates,
        date: null,
        time: null,
        home_team: team1,
        away_team: team2,
        home_score: Number(t1l1),
        away_score: Number(t2l1),
        score: `${Number(t1l1)}–${Number(t2l1)}`,
        stadium: null,
        attendance: null,
        source
      }
    });
  }

  if (t1l2 !== null && t2l2 !== null) {
    out.push({
      json: {
        competition,
        season,
        stage,
        leg: "second_leg",
        round_dates,
        date: null,
        time: null,
        home_team: team2,
        away_team: team1,
        home_score: Number(t2l2),
        away_score: Number(t1l2),
        score: `${Number(t2l2)}–${Number(t1l2)}`,
        stadium: null,
        attendance: null,
        source
      }
    });
  }
}

return out;

// Loop over input items and add a new field called 'myNewField' to the JSON of each one
for (const item of $input.all()) {
  item.json.myNewField = 1;
}

return $input.all();

function cleanText(v) {
  if (v === null || v === undefined) return null;
  const s = String(v).replace(/\s+/g, " ").trim();
  return s || null;
}

const seen = new Set();
const out = [];

for (const item of items) {
  const m = item.json;

  const row = {
    competition: cleanText(m.competition),
    season: cleanText(m.season),
    stage: cleanText(m.stage),
    leg: cleanText(m.leg),
    round_dates: cleanText(m.round_dates),
    date: cleanText(m.date),
    time: cleanText(m.time),
    home_team: cleanText(m.home_team),
    away_team: cleanText(m.away_team),
    home_score: m.home_score ?? null,
    away_score: m.away_score ?? null,
    score: cleanText(m.score),
    stadium: cleanText(m.stadium),
    attendance: m.attendance ?? null,
    source: cleanText(m.source) || "wikipedia"
  };

  if (!row.home_team || !row.away_team || !row.score) continue;

  const key = [
    row.competition,
    row.season,
    row.stage,
    row.leg,
    row.home_team,
    row.away_team,
    row.score
  ].join("|");

  if (seen.has(key)) continue;
  seen.add(key);

  out.push({ json: row });
}

return out;

return [
  {
    json: {
      page: "Anexo:Octavos_de_final_de_la_Liga_de_Campeones_de_la_UEFA_2024-25",
      stage: "round_of_16"
    }
  },
  {
    json: {
      page: "Anexo:Cuartos_de_final_de_la_Liga_de_Campeones_de_la_UEFA_2024-25",
      stage: "quarter_final"
    }
  },
  {
    json: {
      page: "Anexo:Semifinales_de_la_Liga_de_Campeones_de_la_UEFA_2024-25",
      stage: "semi_final"
    }
  },
  {
    json: {
      page: "Final_de_la_Liga_de_Campeones_de_la_UEFA_2024-25",
      stage: "final"
    }
  }
];

return items.map(item => ({
  json: {
    page: item.json.page,
    stage: item.json.stage,
    wikitext: item.json.parse?.wikitext || null
  }
}));

function cleanCell(value) {
  if (!value) return null;

  return String(value)
    // wikilinks
    .replace(/\[\[([^|\]]+)\|([^\]]+)\]\]/g, "$2")
    .replace(/\[\[([^\]]+)\]\]/g, "$1")

    // plantillas comunes
    .replace(/\{\{small\|([^}]+)\}\}/gi, "$1")
    .replace(/\{\{esd\|([^}]+)\}\}/gi, "$1")
    .replace(/\{\{nowrap\|([^}]+)\}\}/gi, "$1")
    .replace(/\{\{bandera2?\|[^}]+\}\}/gi, "")
    .replace(/\{\{flagicon\|[^}]+\}\}/gi, "")
    .replace(/\{\{tc negro\|([^|}]+)\|?([^}]*)\}\}/gi, (_, a, b) => (b || a))
    .replace(/\{\{tc\|([^|}]+)\|?([^}]*)\}\}/gi, (_, a, b) => (b || a))
    .replace(/\{\{.*?\}\}/g, "")

    // basura de estilo wiki
    .replace(/\d+px\|/gi, "")
    .replace(/style="[^"]*"\|/gi, "")
    .replace(/style=[^|]+\|/gi, "")
    .replace(/align=[^|]+\|/gi, "")
    .replace(/bgcolor=[^|]+\|/gi, "")
    .replace(/rowspan="?\d+"?\|/gi, "")
    .replace(/colspan="?\d+"?\|/gi, "")
    .replace(/sort\|/gi, "")
    .replace(/valign=[^|]+\|/gi, "")

    // html
    .replace(/<br\s*\/?>/gi, " ")
    .replace(/<.*?>/g, "")

    // formato
    .replace(/'''/g, "")
    .replace(/''/g, "")
    .replace(/&nbsp;/g, " ")
    .replace(/\|\s*/g, "")
    .replace(/\s+/g, " ")
    .trim();
}

function isScore(v) {
  return /^\d+\s*[–-]\s*\d+$/.test(v || "");
}

function isTime(v) {
  return /^\d{1,2}:\d{2}$/.test(v || "");
}

function isDate(v) {
  return /(\d{1,2}\s+de\s+\w+\s+de\s+\d{4})|(\d{1,2}\s+de\s+\w+)/i.test(v || "");
}

function isAttendance(v) {
  return /^\d{4,6}$/.test(v || "");
}

function normalizeScore(v) {
  return String(v || "").replace(/\s+/g, "").replace("-", "–");
}

const out = [];

for (const item of items) {
  const page = item.json.page || null;
  const stage = item.json.stage || null;
  const wikitext = item.json.wikitext || "";

  // ===== FINAL =====
  if (stage === "final") {
    const homeTeam = cleanCell((wikitext.match(/\|\s*NOMBRE LOCAL\s*=\s*(.+)/i) || [])[1]);
    const awayTeam = cleanCell((wikitext.match(/\|\s*NOMBRE VISITA\s*=\s*(.+)/i) || [])[1]);
    const homeScoreRaw = (wikitext.match(/\|\s*RESULTADO LOCAL\s*=\s*(.+)/i) || [])[1];
    const awayScoreRaw = (wikitext.match(/\|\s*RESULTADO VISITA\s*=\s*(.+)/i) || [])[1];
    const placeRaw = cleanCell((wikitext.match(/\|\s*LUGAR\s*=\s*(.+)/i) || [])[1]);
    const fechaRaw = cleanCell((wikitext.match(/\|\s*FECHA\s*=\s*(.+)/i) || [])[1]);
    const attendanceRaw = cleanCell((wikitext.match(/\|\s*ASISTENTES\s*=\s*(.+)/i) || [])[1]);

    let date = null;
    let time = null;

    if (fechaRaw) {
      const dateMatch = fechaRaw.match(/\d{1,2}\s+de\s+\w+\s+de\s+\d{4}/i);
      const timeMatch = fechaRaw.match(/\d{1,2}:\d{2}/);

      if (dateMatch) date = dateMatch[0];
      if (timeMatch) time = timeMatch[0];
    }

    const homeScore = homeScoreRaw != null ? parseInt(String(homeScoreRaw).replace(/\D/g, ""), 10) : null;
    const awayScore = awayScoreRaw != null ? parseInt(String(awayScoreRaw).replace(/\D/g, ""), 10) : null;
    const attendance = attendanceRaw ? parseInt(String(attendanceRaw).replace(/\D/g, ""), 10) : null;

    if (homeTeam && awayTeam && Number.isInteger(homeScore) && Number.isInteger(awayScore)) {
      out.push({
        page,
        stage,
        leg: "final",
        date,
        time,
        home_team: homeTeam,
        away_team: awayTeam,
        home_score: homeScore,
        away_score: awayScore,
        score: `${homeScore}–${awayScore}`,
        stadium: placeRaw,
        attendance: Number.isInteger(attendance) ? attendance : null,
        source: "wikipedia"
      });
    }

    continue;
  }

  // ===== RESTO DE RONDAS =====
  const tables = wikitext
    .split("{|")
    .slice(1)
    .map(t => "{|" + t.split("|}")[0] + "|}");

  for (const table of tables) {
    const hasResultHeader = /Resultado|Marcador/i.test(table);
    const hasTeamHeader = /Local|Visitante|Equipo/i.test(table);

    if (!hasResultHeader || !hasTeamHeader) continue;

    const rows = table.split("|-").slice(1);

    let currentDate = null;
    let currentTime = null;

    for (const row of rows) {
      const cols = row
        .split("\n")
        .map(l => l.trim())
        .filter(l => l.startsWith("|") && !l.startsWith("|+"))
        .map(l => cleanCell(l.replace(/^\|+/, "")))
        .filter(Boolean);

      if (!cols.length) continue;

      const joinedRaw = cols.join(" ").toLowerCase();

      // saltar cabeceras y basura
      if (joinedRaw.includes("local") && joinedRaw.includes("visitante")) continue;
      if (joinedRaw.includes("partido")) continue;
      if (joinedRaw.includes("resultado") && joinedRaw.includes("estadio")) continue;
      if (joinedRaw.includes("marcador")) continue;

      for (const c of cols) {
        if (isDate(c)) currentDate = c;
        if (isTime(c)) currentTime = c;
      }

      const scoreIndex = cols.findIndex(isScore);
      if (scoreIndex === -1) continue;

      const score = normalizeScore(cols[scoreIndex]);
      const [home_score, away_score] = score.split("–").map(n => parseInt(n, 10));

      const before = cols.slice(0, scoreIndex).filter(v => !isDate(v) && !isTime(v) && !isAttendance(v));
      const after = cols.slice(scoreIndex + 1);

      if (!before.length || !after.length) continue;

      const home_team = before[before.length - 1];
      const away_team = after[0] || null;

      let stadium = null;
      let attendance = null;

      for (const x of after.slice(1)) {
        if (!attendance && isAttendance(x)) {
          attendance = parseInt(x, 10);
        } else if (!stadium && !isAttendance(x) && !isDate(x) && !isTime(x)) {
          stadium = x;
        }
      }

      if (!home_team || !away_team) continue;
      if (!Number.isInteger(home_score) || !Number.isInteger(away_score)) continue;

      out.push({
        page,
        stage,
        leg: null,
        date: currentDate,
        time: currentTime,
        home_team,
        away_team,
        home_score,
        away_score,
        score,
        stadium,
        attendance,
        source: "wikipedia"
      });
    }
  }
}

return out.map(x => ({ json: x }));

function cleanText(v) {
  if (v === null || v === undefined) return null;
  const s = String(v).replace(/\s+/g, " ").trim();
  return s || null;
}

function normalizeTime(v) {
  v = cleanText(v);
  if (!v) return null;
  const m = v.match(/^(\d{1,2}):(\d{2})$/);
  if (!m) return null;
  return `${String(parseInt(m[1], 10)).padStart(2, "0")}:${m[2]}`;
}

const seen = new Set();
const out = [];

for (const item of items) {
  const m = item.json;

  const row = {
    page: cleanText(m.page),
    stage: cleanText(m.stage),
    leg: cleanText(m.leg),
    date: cleanText(m.date),
    time: normalizeTime(m.time),
    home_team: cleanText(m.home_team),
    away_team: cleanText(m.away_team),
    home_score: m.home_score ?? null,
    away_score: m.away_score ?? null,
    score: cleanText(m.score),
    stadium: cleanText(m.stadium),
    attendance: m.attendance ?? null,
    source: cleanText(m.source) || "wikipedia"
  };

  if (!row.home_team || !row.away_team || !row.score) continue;

  const key = [
    row.stage,
    row.date,
    row.time,
    row.home_team,
    row.away_team,
    row.score
  ].join("|");

  if (seen.has(key)) continue;
  seen.add(key);

  out.push({ json: row });
}

return out;
